module edge_detector(CLK, RST, IN_SIG, PULSE);
input CLK, RST, IN_SIG;
output PULSE;
reg PULSE;
reg obf_prev_in_sig;

always @(posedge CLK or posedge RST) begin
    if (RST)
        obf_prev_in_sig <= 0;
    else
        obf_prev_in_sig <= IN_SIG;
end

always @(posedge CLK or posedge RST) begin
    if (RST)
        PULSE <= 0;
    else
        PULSE <= IN_SIG & ~obf_prev_in_sig;
end

endmodule
